import { Decimal } from 'decimal.js';
import { PsbtInput, Tx, TxDetail } from '../types';
import { BtcHotWallet, BtcWallet } from '../wallet';
import { Psbt, Signer } from 'bitcoinjs-lib';
import { UTXO, ScriptType } from '../../chain-base';

export default class TransactionTool<T extends BtcWallet | BtcHotWallet> {
    wallet: T;
    signer?: Signer;
    constructor(wallet: T, hotMode?: boolean);
    signPsbt(psbt: Psbt | string, options?: {
        autoFinalized?: boolean;
        toSignInputs?: {
            index: number;
            sighashTypes: number[];
        }[];
    }): {
        fee: string;
        txId: string;
        rawTx: string;
        txInputs: Tx[];
        txOutputs: Tx[];
        psbtHex: string;
    };
    createPsbtInput(utxo: UTXO, walletOption?: {
        publicKey: string;
        scriptType: ScriptType;
    }): PsbtInput;
    buildTx<T>(utxos: UTXO[], amount: Decimal, feeRate: number, buildPsbtParams: T, buildPsbt: (buildPsbtParams: T, selectedUTXOs: UTXO[], change: Decimal, needChange: boolean) => {
        psbt: Psbt;
        txId: string;
        rawTx: string;
    }, estimateFee?: boolean): TxDetail;
    calculateFee(psbt: Psbt, feeRate: number, estimateFee?: boolean): Decimal;
    selectUTXOs(utxos: UTXO[], targetAmount: Decimal): UTXO[];
    getTotalSatoshi(utxos: UTXO[]): Decimal;
}
